// GENERATED — do not edit by hand. Real Earth elevation, baked for the 'earth'
// landform (batch 66). Equirectangular 512x256 grayscale: ocean = 0, land ramps
// 1..255 with real elevation (Himalaya/Andes bright). North up; left edge is the
// mid-Pacific antimeridian. Source: three-globe's earth-topology displacement
// map (github.com/vasturiano/three-globe, MIT), derived from NASA/NOAA public
// topography. Downsampled from 512x256 via Chromium and re-encoded here.
//
// Lazy-imported: only an 'earth' world pulls this ~171KB chunk.

export const EARTH_W = 512;
export const EARTH_H = 256;

const B64 = '';

let _grid: Uint8Array | null = null;
/** 512x256 row-major grayscale elevation (ocean 0, land 1..255). */
export function earthGrid(): Uint8Array {
  if (_grid) return _grid;
  const bin = atob(B64); // available in browsers and Node ≥16
  const g = new Uint8Array(bin.length);
  for (let i = 0; i < bin.length; i++) g[i] = bin.charCodeAt(i);
  _grid = g;
  return g;
}
